package com.hospital.management.controller.admission;import com.hospital.management.model.*;import com.hospital.management.service.*;import com.hospital.management.service.impl.AdmissionServiceImpl;import javax.servlet.*;import javax.servlet.annotation.WebServlet;import javax.servlet.http.*;import java.io.*;@WebServlet("/admissions/edit")public class AdmissionEditServlet extends HttpServlet{private final AdmissionService service;public AdmissionEditServlet(){this(new AdmissionServiceImpl());}public AdmissionEditServlet(AdmissionService s){service=s;}protected void doGet(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{Long id=AdmissionRequest.id(q.getParameter("id"));Admission a=id==null?null:service.getAdmission(id,AdmissionRequest.user(q)).orElse(null);if(a==null){r.sendError(404);return;}if(!("ADMITTED".equals(a.getStatus())||"TRANSFERRED".equals(a.getStatus()))){r.sendError(409);return;}AdmissionForm f=new AdmissionForm();f.setAdmissionId(a.getAdmissionId());f.setPatientId(a.getPatientId());f.setDoctorId(a.getDoctorId());f.setDepartmentId(a.getDepartmentId());f.setAppointmentId(a.getAppointmentId());f.setBedId(a.getBedId());f.setExpectedDischargeDate(a.getExpectedDischargeDate()==null?null:a.getExpectedDischargeDate().toString());f.setAdmissionReason(a.getAdmissionReason());q.setAttribute("admission",a);q.setAttribute("admissionForm",f);q.getRequestDispatcher("/WEB-INF/views/admissions/edit.jsp").forward(q,r);}protected void doPost(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{AdmissionForm f=AdmissionRequest.admission(q);ServiceResult<Void>x=service.updateAdmission(f,AdmissionRequest.audit(q),AdmissionRequest.user(q));if(x.isSuccess()){r.sendRedirect(q.getContextPath()+"/admissions/view?id="+f.getAdmissionId());return;}q.setAttribute("errors",x.getErrors());q.setAttribute("errorMessage",x.getMessage());doGet(q,r);}}
